-- HKEYETNA seed data

-- Generated starter content for 24 Tunisian governorates.


on conflict (id) do update set slug = excluded.slug, name = excluded.name, icon_name = excluded.icon_name, color_hex = excluded.color_hex, featured_theme = excluded.featured_theme;

on conflict (id) do update set slug = excluded.slug, name = excluded.name, description = excluded.description, hero_image = excluded.hero_image, cover_image = excluded.cover_image, latitude = excluded.latitude, longitude = excluded.longitude, featured_tags = excluded.featured_tags;

on conflict (id) do update set governorate_id = excluded.governorate_id, category_id = excluded.category_id, type = excluded.type, name = excluded.name, description = excluded.description, short_description = excluded.short_description, image_url = excluded.image_url, gallery_urls = excluded.gallery_urls, address = excluded.address, latitude = excluded.latitude, longitude = excluded.longitude, price_min = excluded.price_min, price_max = excluded.price_max, rating = excluded.rating, recommendation_score = excluded.recommendation_score, is_family_friendly = excluded.is_family_friendly, is_local_partner = excluded.is_local_partner, is_active = excluded.is_active, tags = excluded.tags, opening_hours = excluded.opening_hours;

on conflict (place_id) do update set stay_type = excluded.stay_type, nightly_price = excluded.nightly_price, max_guests = excluded.max_guests;

on conflict (place_id) do update set cuisine_type = excluded.cuisine_type, average_meal_price = excluded.average_meal_price, reservation_required = excluded.reservation_required;

on conflict (place_id) do update set craft_type = excluded.craft_type, workshop_duration_hours = excluded.workshop_duration_hours, demo_price = excluded.demo_price;

