insert into governorates (id, slug, name, description, hero_image, cover_image, latitude, longitude, featured_tags) values
  ('20000000-0000-0000-0000-000000000001', 'tunis', 'Tunis', 'Capital energy, medina culture, design addresses, and a quick jump to waterfront life.', 'assets/images/regions/tunis_hero.jpg', 'assets/images/regions/tunis_cover.jpg', 36.8065, 10.1815, ARRAY['Medina', 'Culture', 'Food']),
  ('20000000-0000-0000-0000-000000000002', 'ariana', 'Ariana', 'Residential calm near the capital with gardens, food spots, and access to craft communities.', 'assets/images/regions/ariana_hero.jpg', 'assets/images/regions/ariana_cover.jpg', 36.8663, 10.1647, ARRAY['Family', 'Food', 'Craft']),
  ('20000000-0000-0000-0000-000000000003', 'ben-arous', 'Ben Arous', 'A practical south-of-capital base with local cuisine, artisan clusters, and coastal access.', 'assets/images/regions/ben-arous_hero.jpg', 'assets/images/regions/ben-arous_cover.jpg', 36.7531, 10.2189, ARRAY['Local life', 'Cuisine', 'Access']),
  ('20000000-0000-0000-0000-000000000004', 'manouba', 'Manouba', 'Green pockets, heritage edges, and community-led addresses close to Tunis.', 'assets/images/regions/manouba_hero.jpg', 'assets/images/regions/manouba_cover.jpg', 36.8081, 10.0963, ARRAY['Heritage', 'Gardens', 'Slow travel']),
  ('20000000-0000-0000-0000-000000000005', 'nabeul', 'Nabeul', 'Cap Bon ceramics, beaches, citrus notes, and easy seaside escapes.', 'assets/images/regions/nabeul_hero.jpg', 'assets/images/regions/nabeul_cover.jpg', 36.451, 10.7361, ARRAY['Coast', 'Ceramics', 'Cuisine']),
  ('20000000-0000-0000-0000-000000000006', 'zaghouan', 'Zaghouan', 'Mountain views, Roman heritage, and fresh-air routes just inland from the coast.', 'assets/images/regions/zaghouan_hero.jpg', 'assets/images/regions/zaghouan_cover.jpg', 36.4029, 10.1429, ARRAY['Mountains', 'Roman heritage', 'Hiking']),
  ('20000000-0000-0000-0000-000000000007', 'bizerte', 'Bizerte', 'Northern sea light, medina charm, cliffs, lagoons, and seafood culture.', 'assets/images/regions/bizerte_hero.jpg', 'assets/images/regions/bizerte_cover.jpg', 37.2744, 9.8739, ARRAY['Sea', 'Cliffs', 'Seafood']),
  ('20000000-0000-0000-0000-000000000008', 'beja', 'Beja', 'Rolling farmland, village craft, and generous inland food traditions.', 'assets/images/regions/beja_hero.jpg', 'assets/images/regions/beja_cover.jpg', 36.7333, 9.1833, ARRAY['Countryside', 'Food', 'Agritourism']),
  ('20000000-0000-0000-0000-000000000009', 'jendouba', 'Jendouba', 'Forest edges, Roman heritage, waterfalls, and cool-climate nature breaks.', 'assets/images/regions/jendouba_hero.jpg', 'assets/images/regions/jendouba_cover.jpg', 36.5011, 8.7802, ARRAY['Forests', 'Heritage', 'Nature']),
  ('20000000-0000-0000-0000-000000000010', 'kef', 'Kef', 'Hilltop history, strong regional food, and heritage layers looking over the northwest.', 'assets/images/regions/kef_hero.jpg', 'assets/images/regions/kef_cover.jpg', 36.1742, 8.7049, ARRAY['Hill town', 'History', 'Food']),
  ('20000000-0000-0000-0000-000000000011', 'siliana', 'Siliana', 'Rural calm, rocky panoramas, and community-driven craft and nature experiences.', 'assets/images/regions/siliana_hero.jpg', 'assets/images/regions/siliana_cover.jpg', 36.0833, 9.3667, ARRAY['Panorama', 'Craft', 'Slow routes']),
  ('20000000-0000-0000-0000-000000000012', 'sousse', 'Sousse', 'Beach city rhythm, heritage core, resorts, and lively dining scenes.', 'assets/images/regions/sousse_hero.jpg', 'assets/images/regions/sousse_cover.jpg', 35.8245, 10.6346, ARRAY['Beach', 'Nightlife', 'Heritage']),
  ('20000000-0000-0000-0000-000000000013', 'monastir', 'Monastir', 'Calm waterfront stays, ribat heritage, and polished coastal escapes.', 'assets/images/regions/monastir_hero.jpg', 'assets/images/regions/monastir_cover.jpg', 35.7643, 10.8113, ARRAY['Waterfront', 'Culture', 'Relax']),
  ('20000000-0000-0000-0000-000000000014', 'mahdia', 'Mahdia', 'Soft sea colors, fishing heritage, artisan detail, and low-key luxury.', 'assets/images/regions/mahdia_hero.jpg', 'assets/images/regions/mahdia_cover.jpg', 35.5047, 11.0622, ARRAY['Sea', 'Craft', 'Slow luxury']),
  ('20000000-0000-0000-0000-000000000015', 'sfax', 'Sfax', 'Business energy, strong food identity, island gateways, and artisanal know-how.', 'assets/images/regions/sfax_hero.jpg', 'assets/images/regions/sfax_cover.jpg', 34.7406, 10.7603, ARRAY['Business', 'Food', 'Islands']),
  ('20000000-0000-0000-0000-000000000016', 'kairouan', 'Kairouan', 'Sacred heritage, medina craftsmanship, and deep-rooted culinary traditions.', 'assets/images/regions/kairouan_hero.jpg', 'assets/images/regions/kairouan_cover.jpg', 35.6781, 10.0963, ARRAY['Sacred heritage', 'Craft', 'Cuisine']),
  ('20000000-0000-0000-0000-000000000017', 'kasserine', 'Kasserine', 'Mountain energy, national park edges, and active outdoor escapes.', 'assets/images/regions/kasserine_hero.jpg', 'assets/images/regions/kasserine_cover.jpg', 35.1676, 8.8365, ARRAY['Adventure', 'Mountains', 'Nature']),
  ('20000000-0000-0000-0000-000000000018', 'sidi-bouzid', 'Sidi Bouzid', 'Authentic inland life, farming roots, and practical base camps for local discovery.', 'assets/images/regions/sidi-bouzid_hero.jpg', 'assets/images/regions/sidi-bouzid_cover.jpg', 35.0382, 9.4858, ARRAY['Rural life', 'Food', 'Community']),
  ('20000000-0000-0000-0000-000000000019', 'gabes', 'Gabes', 'Oasis-meets-sea landscapes with date culture, local markets, and southern routes.', 'assets/images/regions/gabes_hero.jpg', 'assets/images/regions/gabes_cover.jpg', 33.8815, 10.0982, ARRAY['Oasis', 'Markets', 'Sea']),
  ('20000000-0000-0000-0000-000000000020', 'medenine', 'Medenine', 'Gateway to ksour villages, island departures, and south-bound cultural routes.', 'assets/images/regions/medenine_hero.jpg', 'assets/images/regions/medenine_cover.jpg', 33.3549, 10.5055, ARRAY['Ksour', 'Islands', 'Culture']),
  ('20000000-0000-0000-0000-000000000021', 'tataouine', 'Tataouine', 'Dramatic desert architecture, troglodyte landscapes, and iconic southern adventure.', 'assets/images/regions/tataouine_hero.jpg', 'assets/images/regions/tataouine_cover.jpg', 32.9297, 10.4518, ARRAY['Desert', 'Ksour', 'Adventure']),
  ('20000000-0000-0000-0000-000000000022', 'gafsa', 'Gafsa', 'Historic oasis gateway with rugged scenery and restorative inland routes.', 'assets/images/regions/gafsa_hero.jpg', 'assets/images/regions/gafsa_cover.jpg', 34.425, 8.7842, ARRAY['Oasis', 'History', 'Nature']),
  ('20000000-0000-0000-0000-000000000023', 'tozeur', 'Tozeur', 'Palm groves, desert cinema landscapes, and premium oasis stays.', 'assets/images/regions/tozeur_hero.jpg', 'assets/images/regions/tozeur_cover.jpg', 33.9197, 8.1335, ARRAY['Oasis', 'Desert', 'Cinema']),
  ('20000000-0000-0000-0000-000000000024', 'kebili', 'Kebili', 'Sahara threshold, dunes, oasis routes, and wide-open adventure design.', 'assets/images/regions/kebili_hero.jpg', 'assets/images/regions/kebili_cover.jpg', 33.7044, 8.969, ARRAY['Sahara', 'Dunes', 'Adventure'])
