  ('30000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 'accommodation', 'Tunis Medina Guest Lodge', 'Flexible stay option in Tunis suited to couples, families, and friends exploring the region.', 'Comfortable guest stay with easy access to local food and activities.', 'assets/images/places/tunis_accommodation_2.jpg', '["assets/images/places/tunis_accommodation_2.jpg", "assets/images/places/tunis_accommodation_22.jpg"]'::jsonb, '14 Tunis Local District', 36.8265, 10.2015, 100, 190, 4.4, 82.4, true, true, true, ARRAY['Nature', 'Comfort', 'Family', 'Medina', 'Culture'], 'Check-in 14:00 / Check-out 11:00'),
